async function requestLCUEdpoint(method: Types.HTTPMethod = "GET", endpoint: string): Promise<{status: boolean, datas: any}> {
    try {
        const url = `${LCUDatas.protocol}://${LCUDatas.address}:${LCUDatas.port}${endpoint}`;
        console.log("url:", url);
        // Get the response whatever the returned status code
        const response = await axios.request({
            method: method,
            url: url,
            headers: {
                'Authorization': `Basic ${Buffer.from(`${LCUDatas.username}:${LCUDatas.password}`).toString('base64')}`,
            },
            httpsAgent: new https.Agent({
                rejectUnauthorized: false,
            }),
            validateStatus: () => true,
        });

        return {
            status: true,
            datas: response.data
        };

    } catch (err) {
        console.log(`[LCU_Worker] Error#001 while fetching api Datas:`, err);
        return {
            status: false,
            datas: null
        };
    }
}

async function requestLiveClientAPIEndpoint(method: Types.HTTPMethod = "GET", endpoint: string, body={}): Promise<{status: boolean, datas: any}> {
    try {

        const url = "https://127.0.0.1:2999" + endpoint;
        console.log(`requestLiveClientAPIEndpoint. ${method} ${url} ${JSON.stringify(body)}`);
        // Get the response whatever the returned status code
        const response = await axios.request({
            method: method,
            url: url,
            headers: {
                'Authorization': `Basic ${Buffer.from(`${LCUDatas.username}:${LCUDatas.password}`).toString('base64')}`,
            },
            httpsAgent: new https.Agent({
                rejectUnauthorized: false,
            }),
            validateStatus: () => true,
            data: body
        });

        return {
            status: true,
            datas: response.data
        };

    } catch (err) {
        console.log(`[LCU_Worker] Error#001 while fetching api Datas:`, err);
        return {
            status: false,
            datas: null
        };
    }
}





class class_POGCardinalInternals {

    constructor() {}
    
    async setCameraPreset(name: string) {
        const presets: {[key: string]: any } = {
            "sequence": {
                "interfaceAll":             false,
                "interfaceAnnounce":        false,
                "interfaceChat":            false,
                "interfaceFrames":          false,
                "interfaceKillCallouts":    false,
                "interfaceMinimap":         false,
                "interfaceNeutralTimers":   false,
                "interfaceQuests":          false,
                "interfaceReplay":          false,
                "interfaceScore":           false,
                "interfaceScoreboard":      false,
                "interfaceTarget":          false,
                "interfaceTimeline":        false,
                "outlineHover":             false,
                "outlineSelect":            false,
            },
            "obs": {
                "interfaceAll":                 true,
                "interfaceAnnounce":            true,
                "interfaceChat":            false,
                "interfaceFrames":              true,
                "interfaceKillCallouts":        true,
                "interfaceMinimap":             true,
                "interfaceNeutralTimers":   false,
                "interfaceQuests":              true,
                "interfaceReplay":          false,
                "interfaceScore":           false,
                "interfaceScoreboard":          true,
                "interfaceTarget":              true,
                "interfaceTimeline":        false,
                "outlineHover":             false,
                "outlineSelect":            false,
            },
            "fight": {
                "interfaceAll":                 true,
                "interfaceAnnounce":            true,
                "interfaceChat":            false,
                "interfaceFrames":          false,
                "interfaceKillCallouts":        true,
                "interfaceMinimap":             true,
                "interfaceNeutralTimers":   false,
                "interfaceQuests":              true,
                "interfaceReplay":          false,
                "interfaceScore":           false,
                "interfaceScoreboard":          true,
                "interfaceTarget":              true,
                "interfaceTimeline":        false,
                "outlineHover":             false,
                "outlineSelect":            false,
            }

        }
        const datas = presets[name]
        requestLiveClientAPIEndpoint("POST", "/replay/render", datas)
    }

    async teleportTo(name:string) {
        let currentRender = await requestLiveClientAPIEndpoint("GET", "/replay/render")
        let currentCameraPosition = currentRender.datas.cameraPosition
        let currentCameraRotation = currentRender.datas.cameraRotation


        let getCurrentY = currentRender.datas.cameraPosition.y
        const positions: {[key: string]: any } = {
            "drake": {
                "cameraPosition": {
                    "x": 10009.052734375,
                    "y": getCurrentY,
                    "z": 3117.9228515625 + 1500
                },
                "cameraRotation": currentCameraRotation
            },
            "nashor": {
                "cameraPosition": {
                    "x": 4958.11474609375,
                    "y": getCurrentY,
                    "z": 8940.5830078125 + 1500
                },
                "cameraRotation": currentCameraRotation
            },
            "topLane": {
                "cameraPosition": {
                    "x": 2289.0458984375,
                    "y": getCurrentY,
                    "z": 11028.00390625 + 1500
                },
                "cameraRotation": currentCameraRotation
            },
            "midLane": {
                "cameraPosition": {
                    "x": 7377.328125,
                    "y": getCurrentY,
                    "z": 5850.9248046875 + 1500
                },
                "cameraRotation": currentCameraRotation
            },
            "botLane": {
                "cameraPosition": {
                    "x": 12581.97265625,
                    "y": getCurrentY,
                    "z": 956.5654296875 + 1500
                },
                "cameraRotation": currentCameraRotation
            }
        }
        const datas = positions[name]
        await requestLiveClientAPIEndpoint("POST", "/replay/render", { cameraMode: "fps", cameraPosition: currentCameraPosition, cameraRotation: currentCameraRotation })
        await requestLiveClientAPIEndpoint("POST", "/replay/render", datas)
        await requestLiveClientAPIEndpoint("POST", "/replay/render", { cameraMode: "top" })
    }
}

