const _CONFIG_filePath = path.resolve(app.getPath('userData') + '/config.json')
// If file not exists, create it

console.log("_CONFIG_filePath:", _CONFIG_filePath)

import express from 'express';


type Config = {
    "appAPI_port": number,
    "dataTrackerPortableBaseURL": `http://${string}:${number}` | `https://${string}:${number}`
}

function getConfig(): Config {
    const defaultData: Config = {
        "appAPI_port": 8201,
        "dataTrackerPortableBaseURL": "http://127.0.0.1:4000"
    }
    if (!fs.existsSync(_CONFIG_filePath)) {
        fs.writeFileSync(_CONFIG_filePath, JSON.stringify(defaultData, null, 4), 'utf8');
    }
    const _CONFIG_ = fs.existsSync(_CONFIG_filePath) ? JSON.parse(fs.readFileSync(_CONFIG_filePath, 'utf8')) : {};
    return _CONFIG_;
}

// Start simple API
const api = express()

api.get("/fightMode/enable", async (req, res) => {
    mainWindow.webContents.send('fightMode', 'enable');
})

api.get("/fightMode/disable", async (req, res) => {
    mainWindow.webContents.send('fightMode', 'disable');
})

api.get("/fightMode/toggleInGame", async (req, res) => {
    try {
        setTimeout(() => {
            console.log("Sending key q")
            sendQ()
        }, 3000)
        return res.send({status: 200, message: `Toggling in game`})
    } catch (e) {
        console.error(e)
        return res.send({status: 500, message: `Error while toggling in game`, stack: e.stack})
    }    
})

api.get("/teleport/:name", async (req, res) => {
    try {
        await POGCardinalInternals.teleportTo(req.params.name)
        return res.send({status: 200, message: `Teleporting to ${req.params.name}`})
    } catch (e) {
        console.error(e)
        return res.send({status: 500, message: `Error while teleporting to ${req.params.name}`, stack: e.stack})
    }
})

api.get("/cameraPreset/:name", async (req, res) => {
    try {
        await POGCardinalInternals.setCameraPreset(req.params.name)
        return res.send({status: 200, message: `Camera preset set to ${req.params.name}`})
    } catch (e) {
        console.error(e)
        return res.send({status: 500, message: `Error while setting camera preset to ${req.params.name}`, stack: e.stack})
    }
    
})

api.get("/overlay/show", (req, res) => {
    console.log("overlay/show")
    mainWindow.webContents.send('toggle_display', 'show');
    _GLOBAL_toggle_display_value = true
    return res.send({status: 200, message: `Overlay shown`})
})

api.get("/overlay/hide", (req, res) => {
    console.log("overlay/hide")
    mainWindow.webContents.send('toggle_display', 'hide');
    _GLOBAL_toggle_display_value = false
    return res.send({status: 200, message: `Overlay hidden`})
})


api.all('*', (req: any, res: any) => {
    
    res.send({
        status: 200,
        message: `You are connected to the API of POGMonitorOverlay on computerName: ${req.hostname}`
    })
})


