let mainWindow: BrowserWindow | null = null;

const createWindow = (): void => {
  // Create the browser window.
  mainWindow = new BrowserWindow({
    fullscreen: true,
    resizable: false,
    // height: 400,
    // width: 600,
    transparent: true, // Make the window transparent
    alwaysOnTop: true,
    frame: false, // Remove the window frame
    webPreferences: {
      preload: MAIN_WINDOW_PRELOAD_WEBPACK_ENTRY,
      nodeIntegration: true,
      contextIsolation: true,
    },
  });

  function toggleMouseEvent(value: boolean) {
    if (value === false) {
      mainWindow.setIgnoreMouseEvents(true, { forward: true });
    } else {
      mainWindow.setIgnoreMouseEvents(false);
    }
  }

  ipcMain.on('mouse-events-disable', (event) => { toggleMouseEvent(false); })
  ipcMain.on('mouse-events-enable', (event) => {  toggleMouseEvent(true); })
  toggleMouseEvent(false);
  // show input box of electron an load the response as URL


  // and load the index.html of the app.
  //mainWindow.loadURL(`${getConfig().dataTrackerPortableBaseURL}/ingame`);
  mainWindow.loadURL(MAIN_WINDOW_WEBPACK_ENTRY)
  // Reput windows on top
  mainWindow.setAlwaysOnTop(true, 'screen-saver');
  

  // set browser window on the 2nd screen
  //mainWindow.setPosition(-1920, 0)
  

  // Open the DevTools.
};

